async function e(e){let t;try{t=await fetch(e)}catch{throw Error(`API not reachable`)}if(!t.ok)throw Error(`HTTP ${t.status}`);if(!(t.headers.get(`content-type`)??``).includes(`json`))throw Error(`not JSON`);try{return await t.json()}catch{throw Error(`JSON parse failed`)}}async function t(t=6){return(await e(`/api/articles.php?count=${t}`)).articles??[]}async function n(t=8){return(await e(`/api/events.php?count=${t}`)).events??[]}async function r(){return(await e(`/api/talks.php`)).talks??[]}export{n,r,t};